  ('dietitian-moex-03594', 'dietitian', 'dietitian-moex-101-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '生物素（biotin）為丙酮酸羧化酶（pyruvate carboxylase）的輔酶，會以共價鍵鍵結於酵素的活化位置，此 活化位置的胺基酸為：', '["leucine", "lysine", "isoleucine", "histidine"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "24514a870de6", "answer_pdf_sha1": "8599ad4fb5bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
