  ('dietitian-moex-03598', 'dietitian', 'dietitian-moex-101-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關油酸、亞麻油酸與次亞麻油酸的敘述，下列何者正確？', '["三者均為飽和脂肪酸", "三者均含有20個碳原子", "在完全氫化後，三者均能產生硬脂酸", "在完全氫化後，三者均可產生許多乙酸斷片（acetate fragments）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "24514a870de6", "answer_pdf_sha1": "8599ad4fb5bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
